from llama_index.core import StorageContext, load_index_from_storage

from datetime import datetime, timedelta

index = load_index_from_storage(StorageContext.from_defaults(persist_dir='./storage'))

stale_docs = 0
for node in index.index_struct.docstore.docs.values():
    if hasattr(node.metadata, 'last_modified'):
        doc_age = datetime.now() - node.metadata['last_modified']
        if doc_age > timedelta(days=30):
            stale_docs += 1

print(f'🚨 STALE DOCS: {stale_docs}/{len(index.index_struct.docstore.docs)}')
